create table dirkspzm32.lvs_packschema_pos (
    sid                varchar2(2 char) not null enable,
    firma_nr           number(2, 0) not null enable,
    packschema_kopf_id varchar2(20 char) not null enable,
    packschema_pos_nr  number(*, 5) not null enable,
    pos_x              number(*, 5) not null enable,
    pos_y              number(*, 5) not null enable,
    rot_xy             number(*, 5) default 0,
    rot_zx             number(*, 5) default 0,
    print_lhm_eti_pos  varchar2(1 char) default 'N' not null enable,
    print_lte_eti_pos  varchar2(1 char) default 'N' not null enable,
    create_date        date,
    create_login_id    number(*, 0),
    change_date        date,
    change_login_id    number(*, 0)
);

alter table dirkspzm32.lvs_packschema_pos
    add constraint pk_lvs_packschema_pos
        primary key ( packschema_kopf_id,
                      packschema_pos_nr,
                      firma_nr,
                      sid )
            using index enable;


